<?php
/**
 * Joke Generator Application
 * 
 * A simple, responsive web application that fetches random jokes
 * from the JokeAPI external API and displays them with a beautiful UI.
 * 
 * Features:
 * - Fetch random jokes from JokeAPI
 * - Display programming and general jokes
 * - Filter jokes by category
 * - Share jokes on social media
 * - Dark/Light theme toggle
 * - Responsive design
 */

// Set error reporting
error_reporting(E_ALL);
ini_set('display_errors', 1);

// Start session
session_start();

// API endpoint
$api_url = 'https://v2.jokeapi.dev/joke/';

// Initialize variables
$joke = null;
$error = null;
$category = isset($_GET['category']) ? $_GET['category'] : 'Any';
$joke_type = isset($_GET['type']) ? $_GET['type'] : 'Any';

// Valid categories
$categories = ['Any', 'General', 'Programming', 'Knock-Knock', 'Dark', 'Spooky', 'Christmas'];
$types = ['Any', 'single', 'twopart'];

// Validate category and type
if (!in_array($category, $categories)) {
    $category = 'Any';
}
if (!in_array($joke_type, $types)) {
    $joke_type = 'Any';
}

/**
 * Fetch joke from API
 */
function fetch_joke($category, $type) {
    global $api_url;
    
    // Build URL with parameters
    $url = $api_url . urlencode($category);
    
    // Add type parameter if not 'Any'
    if ($type !== 'Any') {
        $url .= '?type=' . urlencode($type);
    } else {
        $url .= '?type=single,twopart';
    }
    
    // Add safe filter
    $url .= (strpos($url, '?') ? '&' : '?') . 'safe-mode';
    
    try {
        // Use cURL to fetch data
        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_TIMEOUT, 5);
        curl_setopt($ch, CURLOPT_USERAGENT, 'Mozilla/5.0');\n        \n        $response = curl_exec($ch);
        $http_code = curl_getinfo($ch, CURLINFO_HTTP_CODE);\n        \n        if ($http_code !== 200) {\n            throw new Exception('API Error: HTTP ' . $http_code);\n        }\n        \n        if (curl_errno($ch)) {\n            throw new Exception('cURL Error: ' . curl_error($ch));\n        }\n        \n        curl_close($ch);\n        \n        // Decode JSON\n        $data = json_decode($response, true);\n        \n        if ($data === null) {\n            throw new Exception('Invalid JSON response');\n        }\n        \n        if (isset($data['error']) && $data['error']) {\n            throw new Exception('API Error: ' . ($data['message'] ?? 'Unknown error'));\n        }\n        \n        return $data;\n        \n    } catch (Exception $e) {\n        return null;\n    }\n}\n\n// Handle AJAX request for loading new joke\nif (isset($_GET['action']) && $_GET['action'] === 'get_joke' && isset($_SERVER['HTTP_X_REQUESTED_WITH'])) {\n    header('Content-Type: application/json');\n    \n    $joke_data = fetch_joke($category, $joke_type);\n    \n    if ($joke_data) {\n        echo json_encode([\n            'success' => true,\n            'data' => $joke_data\n        ]);\n    } else {\n        echo json_encode([\n            'success' => false,\n            'error' => 'Failed to fetch joke. Please try again.'\n        ]);\n    }\n    exit;\n}\n\n// Fetch initial joke on page load\nif (!isset($_SESSION['joke_loaded'])) {\n    $joke = fetch_joke($category, $joke_type);\n    $_SESSION['joke_loaded'] = true;\n}\n\n?>\n\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>Random Joke Generator</title>\n    \n    <!-- Bootstrap 5 CSS -->\n    <link href=\"https://cdn.jsdelivr.net/npm/bootstrap@5.1.3/dist/css/bootstrap.min.css\" rel=\"stylesheet\">\n    \n    <!-- Font Awesome Icons -->\n    <link href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0/css/all.min.css\" rel=\"stylesheet\">\n    \n    <style>\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n        \n        :root {\n            --primary-color: #667eea;\n            --secondary-color: #764ba2;\n            --success-color: #28a745;\n            --danger-color: #dc3545;\n            --warning-color: #ffc107;\n            --info-color: #17a2b8;\n            --dark-color: #343a40;\n            --light-color: #f8f9fa;\n        }\n        \n        body {\n            background: linear-gradient(135deg, var(--primary-color) 0%, var(--secondary-color) 100%);\n            min-height: 100vh;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;\n            padding: 20px;\n            transition: all 0.3s ease;\n        }\n        \n        body.dark-mode {\n            background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);\n        }\n        \n        .container-main {\n            max-width: 700px;\n            width: 100%;\n        }\n        \n        .header {\n            text-align: center;\n            color: white;\n            margin-bottom: 40px;\n            animation: slideDown 0.6s ease-out;\n        }\n        \n        .header h1 {\n            font-size: 3rem;\n            font-weight: 700;\n            margin-bottom: 10px;\n            text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.3);\n        }\n        \n        .header p {\n            font-size: 1.1rem;\n            opacity: 0.95;\n        }\n        \n        @keyframes slideDown {\n            from {\n                opacity: 0;\n                transform: translateY(-30px);\n            }\n            to {\n                opacity: 1;\n                transform: translateY(0);\n            }\n        }\n        \n        .card-joke {\n            background: white;\n            border-radius: 20px;\n            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);\n            overflow: hidden;\n            animation: slideUp 0.6s ease-out;\n        }\n        \n        body.dark-mode .card-joke {\n            background: #2a2a3e;\n            color: #ffffff;\n        }\n        \n        @keyframes slideUp {\n            from {\n                opacity: 0;\n                transform: translateY(30px);\n            }\n            to {\n                opacity: 1;\n                transform: translateY(0);\n            }\n        }\n        \n        .card-header {\n            background: linear-gradient(135deg, var(--primary-color) 0%, var(--secondary-color) 100%);\n            color: white;\n            padding: 20px;\n            border: none;\n        }\n        \n        .card-header h5 {\n            margin: 0;\n            font-weight: 600;\n        }\n        \n        .joke-content {\n            padding: 40px 30px;\n            min-height: 200px;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        \n        .joke-text {\n            font-size: 1.5rem;\n            line-height: 1.8;\n            margin-bottom: 20px;\n            color: #333;\n        }\n        \n        body.dark-mode .joke-text {\n            color: #ffffff;\n        }\n        \n        .joke-punchline {\n            font-size: 1.3rem;\n            font-weight: 600;\n            color: var(--primary-color);\n            margin-top: 20px;\n            padding-top: 20px;\n            border-top: 2px solid #eee;\n        }\n        \n        body.dark-mode .joke-punchline {\n            color: #667eea;\n            border-top-color: #444;\n        }\n        \n        .filters {\n            background: white;\n            border-radius: 15px;\n            padding: 20px;\n            margin-bottom: 25px;\n            box-shadow: 0 5px 20px rgba(0, 0, 0, 0.1);\n        }\n        \n        body.dark-mode .filters {\n            background: #2a2a3e;\n        }\n        \n        .filters label {\n            font-weight: 600;\n            color: #333;\n            margin-bottom: 10px;\n            display: block;\n        }\n        \n        body.dark-mode .filters label {\n            color: #ffffff;\n        }\n        \n        .filters select {\n            border: 2px solid #e0e0e0;\n            border-radius: 8px;\n            padding: 10px 15px;\n            font-size: 1rem;\n            transition: all 0.3s ease;\n        }\n        \n        .filters select:focus {\n            outline: none;\n            border-color: var(--primary-color);\n            box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);\n        }\n        \n        .controls {\n            display: flex;\n            gap: 15px;\n            margin-top: 20px;\n            flex-wrap: wrap;\n        }\n        \n        .btn-custom {\n            border: none;\n            border-radius: 10px;\n            padding: 12px 25px;\n            font-weight: 600;\n            font-size: 1rem;\n            cursor: pointer;\n            transition: all 0.3s ease;\n            display: flex;\n            align-items: center;\n            gap: 8px;\n        }\n        \n        .btn-load {\n            background: linear-gradient(135deg, var(--primary-color) 0%, var(--secondary-color) 100%);\n            color: white;\n            flex: 1;\n            min-width: 150px;\n        }\n        \n        .btn-load:hover {\n            transform: translateY(-2px);\n            box-shadow: 0 10px 25px rgba(102, 126, 234, 0.4);\n            color: white;\n            text-decoration: none;\n        }\n        \n        .btn-load:active {\n            transform: translateY(0);\n        }\n        \n        .btn-action {\n            background: #f0f0f0;\n            color: #333;\n            border: 2px solid #e0e0e0;\n        }\n        \n        body.dark-mode .btn-action {\n            background: #3a3a4e;\n            color: #ffffff;\n            border-color: #555;\n        }\n        \n        .btn-action:hover {\n            background: #e0e0e0;\n            color: #333;\n            transform: translateY(-2px);\n            text-decoration: none;\n        }\n        \n        body.dark-mode .btn-action:hover {\n            background: #4a4a5e;\n            color: #ffffff;\n        }\n        \n        .btn-theme {\n            background: white;\n            color: var(--primary-color);\n            border: 2px solid var(--primary-color);\n            margin-left: auto;\n        }\n        \n        body.dark-mode .btn-theme {\n            background: #1a1a2e;\n            color: #667eea;\n            border-color: #667eea;\n        }\n        \n        .btn-theme:hover {\n            background: var(--primary-color);\n            color: white;\n            text-decoration: none;\n        }\n        \n        body.dark-mode .btn-theme:hover {\n            background: #667eea;\n            color: white;\n        }\n        \n        .loading {\n            display: none;\n            text-align: center;\n            padding: 40px;\n        }\n        \n        .spinner-border {\n            color: var(--primary-color);\n        }\n        \n        .error-message {\n            background: #f8d7da;\n            color: #721c24;\n            padding: 15px 20px;\n            border-radius: 10px;\n            margin-bottom: 20px;\n            border-left: 4px solid #dc3545;\n        }\n        \n        body.dark-mode .error-message {\n            background: #5a2c2c;\n            color: #ff9999;\n        }\n        \n        .joke-category {\n            display: inline-block;\n            background: var(--primary-color);\n            color: white;\n            padding: 5px 15px;\n            border-radius: 20px;\n            font-size: 0.85rem;\n            font-weight: 600;\n            margin-bottom: 15px;\n        }\n        \n        .joke-type {\n            display: inline-block;\n            background: var(--info-color);\n            color: white;\n            padding: 5px 12px;\n            border-radius: 20px;\n            font-size: 0.75rem;\n            margin-left: 10px;\n        }\n        \n        .empty-state {\n            text-align: center;\n            padding: 60px 30px;\n            color: white;\n        }\n        \n        .empty-state i {\n            font-size: 4rem;\n            margin-bottom: 20px;\n            opacity: 0.8;\n        }\n        \n        .empty-state h3 {\n            font-size: 1.5rem;\n            margin-bottom: 10px;\n        }\n        \n        .joke-counter {\n            text-align: center;\n            color: white;\n            margin-top: 20px;\n            opacity: 0.8;\n            font-size: 0.9rem;\n        }\n        \n        @media (max-width: 576px) {\n            .header h1 {\n                font-size: 2rem;\n            }\n            \n            .joke-text {\n                font-size: 1.2rem;\n            }\n            \n            .joke-content {\n                padding: 25px 20px;\n            }\n            \n            .controls {\n                flex-direction: column;\n            }\n            \n            .btn-custom {\n                width: 100%;\n                justify-content: center;\n            }\n            \n            .btn-theme {\n                margin-left: 0;\n            }\n        }\n    </style>\n</head>\n<body>\n\n<div class=\"container-main\">\n    <!-- Header -->\n    <div class=\"header\">\n        <h1><i class=\"fas fa-laugh\"></i> Joke Generator</h1>\n        <p>Get a random laugh every time!</p>\n    </div>\n    \n    <!-- Filters -->\n    <div class=\"filters\">\n        <form method=\"GET\" id=\"filterForm\">\n            <div class=\"row\">\n                <div class=\"col-md-6\">\n                    <label for=\"category\">Category:</label>\n                    <select class=\"form-control\" id=\"category\" name=\"category\">\n                        <?php foreach ($categories as $cat): ?>\n                            <option value=\"<?php echo $cat; ?>\" <?php echo ($category === $cat ? 'selected' : ''); ?>>\n                                <?php echo $cat; ?>\n                            </option>\n                        <?php endforeach; ?>\n                    </select>\n                </div>\n                <div class=\"col-md-6\">\n                    <label for=\"type\">Joke Type:</label>\n                    <select class=\"form-control\" id=\"type\" name=\"type\">\n                        <?php foreach ($types as $t): ?>\n                            <option value=\"<?php echo $t; ?>\" <?php echo ($joke_type === $t ? 'selected' : ''); ?>>\n                                <?php echo $t; ?>\n                            </option>\n                        <?php endforeach; ?>\n                    </select>\n                </div>\n            </div>\n            \n            <div class=\"controls\">\n                <button type=\"button\" class=\"btn-custom btn-load\" id=\"loadJokeBtn\">\n                    <i class=\"fas fa-dice\"></i> Get New Joke\n                </button>\n                <button type=\"button\" class=\"btn-custom btn-action\" id=\"copyBtn\">\n                    <i class=\"fas fa-copy\"></i> Copy\n                </button>\n                <button type=\"button\" class=\"btn-custom btn-action\" id=\"shareBtn\">\n                    <i class=\"fas fa-share-alt\"></i> Share\n                </button>\n                <button type=\"button\" class=\"btn-custom btn-theme\" id=\"themeBtn\">\n                    <i class=\"fas fa-moon\"></i>\n                </button>\n            </div>\n        </form>\n    </div>\n    \n    <!-- Joke Card -->\n    <div class=\"card-joke\" id=\"jokeCard\">\n        <?php if ($joke && !isset($joke['error'])): ?>\n            <div class=\"card-header\">\n                <h5>\n                    <i class=\"fas fa-lightbulb\"></i>\n                    <?php echo ucfirst($joke['category']); ?> Joke\n                </h5>\n            </div>\n            <div class=\"joke-content\" id=\"jokeContent\">\n                <div>\n                    <span class=\"joke-category\"><?php echo ucfirst($joke['category']); ?></span>\n                    <span class=\"joke-type\"><?php echo strtoupper($joke['type']); ?></span>\n                </div>\n                \n                <?php if ($joke['type'] === 'single'): ?>\n                    <p class=\"joke-text\" id=\"jokeText\"><?php echo htmlspecialchars($joke['joke']); ?></p>\n                <?php else: ?>\n                    <p class=\"joke-text\" id=\"jokeText\"><?php echo htmlspecialchars($joke['setup']); ?></p>\n                    <p class=\"joke-punchline\" id=\"jokePunchline\"><?php echo htmlspecialchars($joke['delivery']); ?></p>\n                <?php endif; ?>\n            </div>\n        <?php else: ?>\n            <div class=\"empty-state\">\n                <i class=\"fas fa-spinner fa-spin\"></i>\n                <h3>Loading your joke...</h3>\n                <p>Get ready to laugh!</p>\n            </div>\n        <?php endif; ?>\n    </div>\n    \n    <!-- Joke Counter -->\n    <div class=\"joke-counter\">\n        <i class=\"fas fa-info-circle\"></i> Jokes loaded: <span id=\"jokeCount\">1</span>\n    </div>\n</div>\n\n<!-- Bootstrap 5 JS -->\n<script src=\"https://cdn.jsdelivr.net/npm/bootstrap@5.1.3/dist/js/bootstrap.bundle.min.js\"></script>\n\n<script>\n    // Initialize\n    let jokeCount = parseInt(localStorage.getItem('jokeCount')) || 1;\n    document.getElementById('jokeCount').textContent = jokeCount;\n    \n    // Load initial theme\n    if (localStorage.getItem('darkMode') === 'true') {\n        document.body.classList.add('dark-mode');\n        document.getElementById('themeBtn').innerHTML = '<i class=\"fas fa-sun\"></i>';\n    }\n    \n    /**\n     * Load new joke\n     */\n    document.getElementById('loadJokeBtn').addEventListener('click', function() {\n        const category = document.getElementById('category').value;\n        const type = document.getElementById('type').value;\n        \n        this.disabled = true;\n        this.innerHTML = '<i class=\"fas fa-spinner fa-spin\"></i> Loading...';\n        \n        fetch(`?action=get_joke&category=${encodeURIComponent(category)}&type=${encodeURIComponent(type)}`, {\n            headers: {\n                'X-Requested-With': 'XMLHttpRequest'\n            }\n        })\n        .then(response => response.json())\n        .then(data => {\n            if (data.success) {\n                displayJoke(data.data);\n                jokeCount++;\n                document.getElementById('jokeCount').textContent = jokeCount;\n                localStorage.setItem('jokeCount', jokeCount);\n            } else {\n                alert('Error: ' + data.error);\n            }\n        })\n        .catch(error => {\n            console.error('Error:', error);\n            alert('Failed to load joke. Please check your internet connection.');\n        })\n        .finally(() => {\n            this.disabled = false;\n            this.innerHTML = '<i class=\"fas fa-dice\"></i> Get New Joke';\n        });\n    });\n    \n    /**\n     * Display joke\n     */\n    function displayJoke(joke) {\n        const jokeContent = document.getElementById('jokeContent');\n        \n        let html = `\n            <div>\n                <span class=\"joke-category\">${joke.category}</span>\n                <span class=\"joke-type\">${joke.type.toUpperCase()}</span>\n            </div>\n        `;\n        \n        if (joke.type === 'single') {\n            html += `<p class=\"joke-text\" id=\"jokeText\">${escapeHtml(joke.joke)}</p>`;\n        } else {\n            html += `\n                <p class=\"joke-text\" id=\"jokeText\">${escapeHtml(joke.setup)}</p>\n                <p class=\"joke-punchline\" id=\"jokePunchline\">${escapeHtml(joke.delivery)}</p>\n            `;\n        }\n        \n        jokeContent.innerHTML = html;\n        \n        // Update card header\n        const cardHeader = document.querySelector('.card-header');\n        cardHeader.innerHTML = `<h5><i class=\"fas fa-lightbulb\"></i> ${joke.category} Joke</h5>`;\n    }\n    \n    /**\n     * Escape HTML special characters\n     */\n    function escapeHtml(text) {\n        const div = document.createElement('div');\n        div.textContent = text;\n        return div.innerHTML;\n    }\n    \n    /**\n     * Copy joke to clipboard\n     */\n    document.getElementById('copyBtn').addEventListener('click', function() {\n        const jokeText = document.getElementById('jokeText').textContent;\n        const punchline = document.getElementById('jokePunchline');\n        let fullJoke = jokeText;\n        \n        if (punchline) {\n            fullJoke += '\\n' + punchline.textContent;\n        }\n        \n        navigator.clipboard.writeText(fullJoke).then(() => {\n            const originalText = this.innerHTML;\n            this.innerHTML = '<i class=\"fas fa-check\"></i> Copied!';\n            setTimeout(() => {\n                this.innerHTML = originalText;\n            }, 2000);\n        }).catch(err => {\n            alert('Failed to copy to clipboard');\n        });\n    });\n    \n    /**\n     * Share joke\n     */\n    document.getElementById('shareBtn').addEventListener('click', function() {\n        const jokeText = document.getElementById('jokeText').textContent;\n        const shareText = '😂 ' + jokeText;\n        \n        if (navigator.share) {\n            navigator.share({\n                title: 'Random Joke',\n                text: shareText,\n                url: window.location.href\n            }).catch(err => console.error('Share error:', err));\n        } else {\n            // Fallback: Show share options\n            const twitterUrl = `https://twitter.com/intent/tweet?text=${encodeURIComponent(shareText)}&url=${encodeURIComponent(window.location.href)}`;\n            const facebookUrl = `https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(window.location.href)}`;\n            \n            alert(`Share this joke:\\n\\n${shareText}\\n\\nTwitter: ${twitterUrl}\\n\\nFacebook: ${facebookUrl}`);\n        }\n    });\n    \n    /**\n     * Toggle dark mode\n     */\n    document.getElementById('themeBtn').addEventListener('click', function() {\n        const isDarkMode = document.body.classList.toggle('dark-mode');\n        localStorage.setItem('darkMode', isDarkMode);\n        \n        this.innerHTML = isDarkMode \n            ? '<i class=\"fas fa-sun\"></i>' \n            : '<i class=\"fas fa-moon\"></i>';\n    });\n    \n    /**\n     * Filter form submission\n     */\n    document.getElementById('filterForm').addEventListener('submit', function(e) {\n        e.preventDefault();\n        document.getElementById('loadJokeBtn').click();\n    });\n</script>\n\n</body>\n</html>\n